// Agent Office - Pixelmon Edition
// Frontend Application

const API_BASE = '';
const REFRESH_INTERVAL = 5000;
let refreshTimer = null;
let agents = [];

// DOM Elements
const officeGrid = document.getElementById('officeGrid');
const emptyState = document.getElementById('emptyState');
const teamCount = document.getElementById('teamCount');
const teamsCount = document.getElementById('teamsCount');
const tasksActive = document.getElementById('tasksActive');
const currentTime = document.getElementById('currentTime');
const loadingOverlay = document.getElementById('loadingOverlay');

// Modals
const hireModal = document.getElementById('hireModal');
const hireForm = document.getElementById('hireForm');
const hireBtn = document.getElementById('hireBtn');
const refreshBtn = document.getElementById('refreshBtn');
const closeHireModal = document.getElementById('closeHireModal');
const cancelHire = document.getElementById('cancelHire');

const detailModal = document.getElementById('agentDetailModal');
const closeDetailModal = document.getElementById('closeDetailModal');
const detailTitle = document.getElementById('detailTitle');
const detailSprite = document.getElementById('detailSprite');
const detailName = document.getElementById('detailName');
const detailTeam = document.getElementById('detailTeam');
const detailType = document.getElementById('detailType');
const detailDescription = document.getElementById('detailDescription');
const saveDescription = document.getElementById('saveDescription');

// Let's create a detailed Pixelmon-style office dashboard
// Update time display
function updateTime() {
  const now = new Date();
  currentTime.textContent = now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: false });
}

// Fetch agents from API
async function fetchAgents() {
  try {
    const response = await fetch(`${API_BASE}/api/agents`);
    const data = await response.json();
    return data.agents || [];
  } catch (err) {
    console.error('Failed to fetch agents:', err);
    return [];
  }
}

// Fetch teams from API
async function fetchTeams() {
  try {
    const response = await fetch(`${API_BASE}/api/teams`);
    const data = await response.json();
    return data.teams || [];
  } catch (err) {
    console.error('Failed to fetch teams:', err);
    return [];
  }
}

// Determine agent status based on tasks
function getAgentStatus(agent) {
  // Default status based on what we know
  return 'idle'; // working, idle, planning
}

// Get agent type class
function getAgentTypeClass(type) {
  const map = {
    'general-purpose': 'General',
    'Explore': 'Explorer',
    'Plan': 'Architect',
    'code-reviewer': 'Reviewer'
  };
  return map[type] || 'Default';
}

function getAgentTypeClassLower(type) {
  const map = {
    'general-purpose': 'general',
    'Explore': 'explorer',
    'Plan': 'architect',
    'code-reviewer': 'reviewer'
  };
  return map[type] || 'default';
}

// Get sprite class based on type
function getSpriteClass(type) {
  const map = {
    'general-purpose': 'pixel-sprite-general',
    'Explore': 'pixel-sprite-explorer',
    'Plan': 'pixel-sprite-architect',
    'code-reviewer': 'pixel-sprite-reviewer'
  };
  return map[type] || 'pixel-sprite-general';
}

// Create agent card HTML
function createAgentCard(agent) {
  const status = getAgentStatus(agent);
  const typeClass = getAgentTypeClass(agent.type);
  const typeClassLower = getAgentTypeClassLower(agent.type);
  const spriteClass = getSpriteClass(agent.type);
  const desc = agent.description || '';
  const descClass = desc ? '' : 'empty';
  const descText = desc || 'No description yet...';

  return `
    <div class="agent-card type-${typeClass}" data-agent-id="${agent.id}" data-team="${agent.teamName}">
      <div class="card-header">
        <div style="display:flex;align-items:center;gap:8px;">
          <span class="card-name">${agent.name}</span>
          <div class="status-indicator ${status}"></div>
        </div>
        <span class="card-level">${agent.teamName}</span>
      </div>
      <div class="card-body">
        <div class="sprite-container">
          <div class="pixel-sprite ${spriteClass}"></div>
        </div>
      </div>
      <div class="card-type-banner type-${typeClassLower}">${typeClass}</div>
      <div class="card-stats">
        <span class="stat-bar-label">HP</span>
        <div class="stat-bar">
          <div class="stat-bar-fill high" style="width: ${60 + Math.floor(Math.random() * 40)}%"></div>
        </div>
        <span class="stat-bar-text">${status.toUpperCase()}</span>
      </div>
      <div class="card-description ${descClass}" onclick="openAgentDetail('${agent.id}')">${descText}</div>
      <div class="card-footer">
        <button class="btn pixel-btn btn-edit" onclick="openAgentDetail('${agent.id}')">Inspect</button>
        <button class="btn pixel-btn btn-shut" onclick="shutDownTeam('${agent.teamName}')">Shut Down</button>
      </div>
    </div>
  `;
}

// Render the full office with areas
function renderOffice(agentList, teamList) {
  let html = '';

  // Update stats
  teamCount.textContent = agentList.length;
  teamsCount.textContent = teamList.length;

  let totalActiveTasks = 0;
  teamList.forEach(t => {
    totalActiveTasks += t.taskStatus?.inProgress || 0;
  });
  tasksActive.textContent = totalActiveTasks;

  if (agentList.length === 0) {
    // Show empty state
    html = `
      <div class="empty-state" id="emptyState">
        <div class="empty-pokemon"></div>
        <p class="empty-text">No agents running!</p>
        <p class="empty-hint">Click <strong>+ Hire Agent</strong> or start a Claude session with <code class="pixel-code">claude "your task"</code></p>
      </div>
    `;
  } else {
    // Active Work Area - Agents that are working
    const workingAgents = agentList.filter(a => getAgentStatus(a) === 'working');
    const idleAgents = agentList.filter(a => getAgentStatus(a) === 'idle');
    const planningAgents = agentList.filter(a => getAgentStatus(a) === 'planning');

    // Office Main Area (Working agents)
    html += `
      <div class="area-header area-working">
        <h2 class="area-title">🏢 Office - Active Work Area</h2>
        <span class="area-count">${workingAgents.length || agentList.length} agent${(workingAgents.length || agentList.length) !== 1 ? 's' : ''} working</span>
      </div>
    `;

    (workingAgents.length > 0 ? workingAgents : agentList).forEach(agent => {
      html += createAgentCard(agent);
    });

    // Resting Rooms (Idle agents)
    if (idleAgents.length > 0) {
      html += `
        <div class="area-header area-resting">
          <h2 class="area-title">🛋️ Resting Room</h2>
          <span class="area-count">${idleAgents.length} agent${idleAgents.length !== 1 ? 's' : ''} resting</span>
        </div>
      `;

      idleAgents.forEach(agent => {
        html += createAgentCard(agent);
      });
    }

    // Sports Area
    html += `
      <div class="area-header area-sports">
        <h2 class="area-title">🏟️ Sports & Recreation Area</h2>
        <span class="area-count">2 courts available</span>
      </div>
    `;

    // Tennis court
    html += createSportsCard('tennis');
    // Basketball court
    html += createSportsCard('basketball');

    // Planning Area
    if (planningAgents.length > 0) {
      html += `
        <div class="area-header area-planning">
          <h2 class="area-title">📋 Planning Room</h2>
          <span class="area-count">${planningAgents.length} agent${planningAgents.length !== 1 ? 's' : ''} planning</span>
        </div>
      `;

      planningAgents.forEach(agent => {
        html += createAgentCard(agent);
      });
    }
  }

  officeGrid.innerHTML = html;
}

// Create sports area card
function createSportsCard(sport) {
  const isTennis = sport === 'tennis';
  const bgClass = isTennis ? 'tennis' : 'basketball';

  return `
    <div class="sports-card sports-${bgClass}">
      <div class="sports-field">
        ${isTennis ? `
          <div class="tennis-court">
            <div class="court-net"></div>
            <div class="court-line"></div>
            <div class="court-line-v"></div>
            <div class="tennis-ball"></div>
          </div>
        ` : `
          <div class="basketball-court">
            <div class="hoop"></div>
            <div class="court-paint"></div>
            <div class="free-throw-circle"></div>
            <div class="three-point-line"></div>
            <div class="basketball"></div>
          </div>
        `}
      </div>
      <div class="card-footer">
        <span class="sports-label">${isTennis ? '🎾 Tennis' : '🏀 Basketball'} Court</span>
        <span class="sports-status">Available</span>
      </div>
    </div>
  `;
}

// Open agent detail modal
function openAgentDetail(agentId) {
  const agent = agents.find(a => a.id === agentId || a.name === agentId);
  if (!agent) return;

  detailTitle.textContent = agent.name;
  detailName.textContent = `Name: ${agent.name}`;
  detailTeam.textContent = `Team: ${agent.teamName}`;
  detailType.textContent = `Type: ${getAgentTypeClass(agent.type)}`;
  detailDescription.value = agent.description || '';

  // Set sprite
  const spriteClass = getSpriteClass(agent.type);
  detailSprite.innerHTML = `<div class="pixel-sprite ${spriteClass}"></div>`;

  detailModal.dataset.agentId = agentId;
  detailModal.classList.add('visible');
}

// Save agent description
async function saveAgentDescription(agentId, description) {
  try {
    await fetch(`${API_BASE}/api/agents/${agentId}/description`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ description })
    });
    showNotification(`Description saved for ${agentId}!`);
  } catch (err) {
    console.error('Failed to save description:', err);
  }
}

// Shut down a team
async function shutDownTeam(teamName) {
  if (!confirm(`Shut down team "${teamName}"? This will clean up all agents in this team.`)) return;

  try {
    const response = await fetch(`${API_BASE}/api/teams/${teamName}`, {
      method: 'DELETE'
    });
    const data = await response.json();
    if (data.success) {
      showNotification(`Team "${teamName}" shut down!`);
      refreshData();
    }
  } catch (err) {
    console.error('Failed to shut down team:', err);
  }
}

// Show notification
function showNotification(message) {
  const notif = document.createElement('div');
  notif.className = 'battle-notification';
  notif.textContent = message;
  document.body.appendChild(notif);

  setTimeout(() => {
    notif.style.animation = 'slideUp 0.3s steps(3) reverse';
    setTimeout(() => notif.remove(), 300);
  }, 2000);
}

// Refresh all data
async function refreshData() {
  agents = await fetchAgents();
  const teams = await fetchTeams();
  renderOffice(agents, teams);
  loadingOverlay.classList.add('hidden');
}

// Start auto-refresh
function startAutoRefresh() {
  if (refreshTimer) clearInterval(refreshTimer);
  refreshTimer = setInterval(() => {
    refreshData();
  }, REFRESH_INTERVAL);
}

// Update time every second
function startTimeUpdate() {
  updateTime();
  setInterval(updateTime, 1000);
}

// Event Listeners
hireBtn.addEventListener('click', () => {
  hireModal.classList.add('visible');
});

closeHireModal.addEventListener('click', () => {
  hireModal.classList.remove('visible');
});

cancelHire.addEventListener('click', () => {
  hireModal.classList.remove('visible');
});

closeDetailModal.addEventListener('click', () => {
  detailModal.classList.remove('visible');
});

detailModal.addEventListener('click', (e) => {
  if (e.target === detailModal) {
    detailModal.classList.remove('visible');
  }
});

saveDescription.addEventListener('click', () => {
  const agentId = detailModal.dataset.agentId;
  saveAgentDescription(agentId, detailDescription.value);
});

hireForm.addEventListener('submit', async (e) => {
  e.preventDefault();

  const name = document.getElementById('agentName').value;
  const role = document.getElementById('agentRole').value;
  const prompt = document.getElementById('agentPrompt').value;
  const description = document.getElementById('agentDescription').value;

  const fullPrompt = prompt || `${name} is a ${role} agent that helps with tasks.`;

  try {
    const response = await fetch(`${API_BASE}/api/agents`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        name,
        role,
        prompt: fullPrompt,
        description
      })
    });

    const data = await response.json();
    if (data.success) {
      showNotification(`To spawn "${name}", run:\n${data.command}`);
    }
  } catch (err) {
    console.error('Failed to create agent:', err);
  }

  hireModal.classList.remove('visible');
  hireForm.reset();
});

refreshBtn.addEventListener('click', () => {
  refreshData();
  showNotification('Refreshing...');
});

// Close modals with Escape key
document.addEventListener('keydown', (e) => {
  if (e.key === 'Escape') {
    hireModal.classList.remove('visible');
    detailModal.classList.remove('visible');
  }
});

// Initialize
startTimeUpdate();
refreshData();
startAutoRefresh();

