/* --- Area Headers --- */

.area-header {
  grid-column: 1 / -1;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 16px;
  border: var(--border-thick) solid var(--panel-border);
  margin-top: 8px;
  position: relative;
}

.area-working {
  background: linear-gradient(90deg, var(--poke-blue), var(--poke-dark-blue));
}

.area-resting {
  background: linear-gradient(90deg, var(--poke-orange), var(--poke-gold));
}

.area-sports {
  background: linear-gradient(90deg, var(--poke-green), #2e7d32);
}

.area-planning {
  background: linear-gradient(90deg, var(--poke-purple), #6a1b9a);
}

.area-title {
  font-family: var(--font-title);
  font-size: 0.9rem;
  color: #fff;
  text-shadow: 2px 2px 0 rgba(0,0,0,0.3);
}

.area-count {
  font-family: var(--font-title);
  font-size: 0.6rem;
  color: rgba(255,255,255,0.8);
}

/* --- Sports Cards --- */
.sports-card {
  border: var(--border-thick) solid var(--panel-border);
  overflow: hidden;
  position: relative;
  animation: wildAppear 0.4s steps(6);
}

.sports-field {
  height: 200px;
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
}

/* Tennis Court */
.sports-tennis .sports-field {
  background:
    linear-gradient(180deg, #2e7d32 0%, #4caf50 50%, #2e7d32 100%);
}

.tennis-court {
  width: 280px;
  height: 140px;
  background: #5c9e5c;
  border: 3px solid #fff;
  position: relative;
}

.court-net {
  position: absolute;
  left: 50%;
  top: -4px;
  bottom: -4px;
  width: 4px;
  background: #fff;
  transform: translateX(-50%);
}

.court-line {
  position: absolute;
  top: 50%;
  left: 0;
  right: 0;
  height: 2px;
  background: rgba(255,255,255,0.7);
}

.court-line-v {
  position: absolute;
  left: 50%;
  top: 0;
  bottom: 0;
  width: 2px;
  background: rgba(255,255,255,0.7);
  transform: translateX(-50%);
}

.tennis-ball {
  width: 16px;
  height: 16px;
  background: #c8e632;
  border: 2px solid #a8c42a;
  border-radius: 50%;
  position: absolute;
  top: 35%;
  left: 35%;
  animation: tennisBounce 0.8s ease-in-out infinite;
  box-shadow: 2px 2px 0 rgba(0,0,0,0.2);
}

@keyframes tennisBounce {
  0%, 100% { transform: translate(0, 0); }
  25% { transform: translate(20px, -12px); }
  50% { transform: translate(40px, 0); }
  75% { transform: translate(60px, -8px); }
}

/* Basketball Court */
.sports-basketball .sports-field {
  background: linear-gradient(180deg, #a0522d 0%, #cd853f 50%, #a0522d 100%);
}

.basketball-court {
  width: 280px;
  height: 140px;
  background: #d4a76a;
  border: 3px solid #fff;
  position: relative;
}

.hoop {
  width: 24px;
  height: 24px;
  border: 3px solid #ff5722;
  border-radius: 50%;
  position: absolute;
  right: 16px;
  top: 50%;
  transform: translateY(-50%);
  background: transparent;
}

.hoop::after {
  content: '';
  position: absolute;
  top: -8px;
  left: -8px;
  width: 40px;
  height: 40px;
  border: 2px solid rgba(255,87,34,0.3);
}

.court-paint {
  position: absolute;
  right: 0;
  top: 50%;
  transform: translateY(-50%);
  width: 60px;
  height: 80px;
  background: rgba(255,87,34,0.2);
  border-left: 2px solid #fff;
}

.free-throw-circle {
  position: absolute;
  right: 60px;
  top: 50%;
  transform: translateY(-50%);
  width: 40px;
  height: 40px;
  border: 2px solid #fff;
  border-radius: 50%;
}

.three-point-line {
  position: absolute;
  right: 0;
  top: 50%;
  transform: translateY(-50%);
  width: 80px;
  height: 120px;
  border: 2px solid rgba(255,255,255,0.5);
  border-radius: 0 0 60px 60px / 0 0 100px 100px;
}

.basketball {
  width: 20px;
  height: 20px;
  background: #ff6d00;
  border: 2px solid #e65100;
  border-radius: 50%;
  position: absolute;
  top: 20%;
  left: 30%;
  animation: basketballBounce 1s ease-in-out infinite;
  box-shadow: 2px 2px 0 rgba(0,0,0,0.3);
}

.basketball::before {
  content: '';
  position: absolute;
  top: 50%;
  left: 2px;
  right: 2px;
  height: 1px;
  background: #e65100;
}

.basketball::after {
  content: '';
  position: absolute;
  left: 50%;
  top: 2px;
  bottom: 2px;
  width: 1px;
  background: #e65100;
}

@keyframes basketballBounce {
  0%, 100% { transform: translate(0, 0) scale(1); }
  30% { transform: translate(10px, -16px) scale(1.05, 0.95); }
  60% { transform: translate(30px, 0) scale(0.95, 1.05); }
}

.sports-card .card-footer {
  display: flex;
  justify-content: space-between;
  padding: 10px 12px;
  background: #e0e0e8;
}

.sports-label {
  font-family: var(--font-title);
  font-size: 0.6rem;
  color: var(--text-primary);
}

.sports-status {
  font-family: var(--font-title);
  font-size: 0.6rem;
  color: var(--poke-green);
}

