file.content:
  padding: 4px 12px;
  font-family: var(--font-title);
  font-size: 0.5rem;
  text-align: center;
  text-transform: uppercase;
  letter-spacing: 2px;
  color: #fff;
  border-top: var(--border-thin) solid var(--panel-border);
}

.card-type-banner.type-general { background: var(--poke-blue); }
.card-type-banner.type-explorer { background: var(--poke-green); }
.card-type-banner.type-architect { background: var(--poke-purple); }
.card-type-banner.type-reviewer { background: var(--poke-orange); }
.card-type-banner.type-default { background: var(--poke-teal); }

/* Card Description */
.card-description {
  padding: 12px;
  font-size: 0.7rem;
  line-height: 2;
  color: var(--text-secondary);
  background: var(--panel-bg);
  border-top: var(--border-thin) solid var(--panel-border);
  min-height: 48px;
}

.card-description.empty {
  color: var(--text-muted);
  font-style: oblique;
}

/* Card Footer - Actions */
.card-footer {
  display: flex;
  justify-content: space-between;
  padding: 8px 12px;
  background: #e0e0e8;
  border-top: var(--border-thin) solid var(--panel-border);
}

.card-footer .btn {
  font-size: 0.6rem;
  padding: 6px 10px;
}

.btn-fire {
  background: var(--poke-pink);
  color: #fff;
  border-color: #d32f2f;
}

.btn-edit {
  background: var(--poke-yellow);
  color: var(--panel-border);
  border-color: var(--poke-gold);
}

.btn-shut {
  background: var(--poke-red);
  color: #fff;
  border-color: #cc0000;
}

/* --- Health/Stats Bar (like HP bar) --- */
.card-stats {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 6px 12px;
  background: #f0f0f0;
  border-top: var(--border-thin) solid var(--panel-border);
  border-bottom: var(--border-thin) solid var(--panel-border);
}

.stat-bar-label {
  font-family: var(--font-title);
  font-size: 0.5rem;
  color: var(--text-secondary);
  min-width: 40px;
}

.stat-bar {
  flex: 1;
  height: 8px;
  background: #ccc;
  border: var(--border-thin) solid var(--panel-border);
  position: relative;
  overflow: hidden;
}

.stat-bar-fill {
  height: 100%;
  position: absolute;
  left: 0;
  top: 0;
  animation-fill-mode: both;
}

.stat-bar-fill.high {
  background: var(--poke-green);
  animation: fillBar 1s steps(8) forwards;
}

.stat-bar-fill.medium {
  background: var(--poke-yellow);
}

.stat-bar-fill.low {
  background: var(--poke-pink);
}

@keyframes fillBar {
  from { width: 0; }
}

.stat-bar-text {
  font-family: var(--font-title);
  font-size: 0.5rem;
  color: var(--text-secondary);
  min-width: 50px;
  text-align: right;
}

/* --- Empty State --- */
.empty-state {
  grid-column: 1 / -1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  min-height: 400px;
  background: rgba(0,0,0,0.3);
  border: var(--border-thick) solid var(--gb-dark);
  color: var(--gb-light);
  animation: fadeIn 0.5s steps(4);
}

@keyframes fadeIn {
  from { opacity: 0; transform: scale(0.95); }
  to { opacity: 1; transform: scale(1); }
}

.empty-pokemon {
  width: 64px;
  height: 64px;
  position: relative;
  margin-bottom: 32px;
}

.empty-pokemon::before {
  content: '';
  position: absolute;
  width: 48px;
  height: 48px;
  left: 8px;
  top: 8px;
  background: var(--gb-mid);
  border: var(--border-thick) solid var(--gb-dark);
  box-shadow:
    inset -4px -4px 0 0 var(--gb-dark),
    inset 4px 4px 0 0 var(--gb-light),
    /* Pokeball line */
    48px 0 0 var(--gb-dark),
    -48px 0 0 var(--gb-dark),
    /* Pokeball button */
    0 20px 8px var(--gb-light),
    0 28px 8px var(--gb-dark),
    /* Eyes */
    12px 12px var(--gb-black),
    32px 12px var(--gb-black);
  animation: bounce 1s steps(4) infinite;
}

@keyframes bounce {
  0%, 100% { transform: translateY(0) rotate(0deg); }
  25% { transform: translateY(-8px); }
  75% { transform: translateY(4px); }
}

.empty-text {
  font-family: var(--font-title);
  font-size: 1.4rem;
  color: var(--gb-light);
  text-shadow: 2px 2px 0 var(--gb-dark);
  margin-bottom: 16px;
  text-align: center;
  line-height: 2.5;
}

.empty-hint {
  font-size: 0.7rem;
  color: var(--gb-mid);
  text-align: center;
  line-height: 2.5;
  max-width: 400px;
}

.pixel-code {
  font-family: 'Press Start 2P', monospace;
  background: rgba(15,56,15,0.5);
  padding: 4px 8px;
  border: var(--border-thin) solid var(--gb-mid);
  color: var(--gb-light);
  font-size: 0.6rem;
}

