    -50px 60px 0 rgba(255,196,0,0.3),
    200px 80px 0 rgba(255,196,0,0.4),
    -100px 100px 0 var(--poke-yellow),
    80px 120px 0 rgba(255,196,0,0.6),
    240px 140px 0 var(--poke-yellow);
  animation: twinkle 2s steps(2) infinite;
  z-index: -1;
  pointer-events: none;
}

@keyframes twinkle {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.3; }
}

/* --- Battle message style notifications --- */
.battle-notification {
  position: fixed;
  bottom: 80px;
  left: 50%;
  transform: translateX(-50%);
  background: var(--panel-bg);
  border: var(--border-thick) solid var(--panel-border);
  padding: 16px 24px;
  font-family: var(--font-title);
  font-size: 0.8rem;
  color: var(--text-primary);
  z-index: 1000;
  animation: slideUp 0.3s steps(3);
  box-shadow:
    4px 4px 0 rgba(0,0,0,0.3),
    inset 2px 2px 0 #fff;
}

@keyframes slideUp {
  from { transform: translateX(-50%) translateY(20px); opacity: 0; }
  to { transform: translateX(-50%) translateY(0); opacity: 1; }
}

