    <span style="background:#2a2a4e;color:#8bac0f;padding:4px 8px;">${cmd}</span><br><br>
    Or copy the prompt and paste after <code>claude</code>:<br>
    <span style="font-size:0.6rem;color:#6a6a8e;">${fullPrompt.substring(0, 100)}${fullPrompt.length > 100 ? '...' : ''}</span>
  `;

  hireForm.innerHTML = `
    <div style="text-align:center;padding:20px 0;">
      ${instructions}
      <div style="margin-top:20px;">
        <button class="btn pixel-btn btn-hire" onclick="copyToClipboard('${cmd.replace(/'/g, "\\'")}')">Copy Command</button>
      </div>
      <div style="margin-top:12px;">
        <button class="btn pixel-btn" onclick="resetHireForm()">Hire Another</button>
      </div>
    </div>
  `;
});

refreshBtn.addEventListener('click', () => {
  refreshData();
  showNotification('Refreshing...');
});

// Close modals with Escape key
document.addEventListener('keydown', (e) => {
  if (e.key === 'Escape') {
    hireModal.classList.remove('visible');
    detailModal.classList.remove('visible');
  }
});

// Rebind form submit handler (was replaced above)
function rebindFormSubmit() {
  const newForm = document.getElementById('hireForm');
  newForm.removeEventListener('submit', hireFormHandler);
  newForm.addEventListener('submit', async (e) => {
    e.preventDefault();
    hireFormHandler(e);

    const nameVal = document.getElementById('agentName')?.value || '';
    const roleVal = document.getElementById('agentRole')?.value || '';
    const promptVal = document.getElementById('agentPrompt')?.value || '';
    const descVal = document.getElementById('agentDescription')?.value || '';
    const fullPrompt = promptVal || `${nameVal} is a ${roleVal} agent that helps with tasks.`;
    const cmd = `claude "${fullPrompt}"`;

    const instructions = `
      <strong>🐾 Agent "${nameVal}" Ready!</strong><br><br>
      <strong>Run this in your terminal:</strong><br>
      <span onclick="copyToClipboard('${cmd.replace(/'/g, "\\'")}')" style="background:#2a2a4e;color:#8bac0f;padding:6px 12px;cursor:pointer;display:inline-block;margin:8px 0;" title="Click to copy">${cmd}</span><br>
      <span style="font-size:0.5rem;color:#6a6a8e;">(click to copy)</span><br><br>
      <div style="margin-top:12px;">
        <button class="btn pixel-btn btn-hire" onclick="copyToClipboard('${cmd.replace(/'/g, "\\'")}')">Copy Command</button>
      </div>
      <div style="margin-top:12px;">
        <button class="btn pixel-btn" onclick="resetHireForm()">Hire Another</button>
      </div>
    `;

    hireForm.innerHTML = `
      <div style="text-align:center;padding:20px 0;">
        ${instructions}
      </div>
    `;
  });
}

// Initialize
startTimeUpdate();
refreshData();
startAutoRefresh();
bindHireForm();

